const subject = (email.subject || '').toLowerCase();
const from = (email.from?.emailAddress?.address || '').toLowerCase();
const fromName = (email.from?.emailAddress?.name || '').toLowerCase();
const body = (email.bodyPreview || email.body?.content || '').toLowerCase();

// Padrões de emails de planilhas que devem ser ignorados
const planilhaPatterns = [
  'automated daily shipment',
  'standard daily order',
  'daily shipment report',
  'order confirmation',
  '.xlsx',
  '.xls',
  'attached spreadsheet',
  'planilha anexa',
  'daily order'
];

// Remetentes/fornecedores que devem ser ignorados
const ignoredSenders = [
  'biorad',
  'bio-rad',
  'bio rad',
  'order vision',
  'ordervision'
];

// Verificar se é email de planilha
const isPlanilha = planilhaPatterns.some(pattern => 
  subject.includes(pattern) || body.includes(pattern)
);

// Verificar se é de remetente ignorado
const isIgnoredSender = ignoredSenders.some(sender => 
  from.includes(sender) || 
  fromName.includes(sender) || 
  subject.includes(sender) ||
  body.includes(sender)
);

// Verificar se tem anexos (planilhas geralmente têm)
const hasAttachments = email.hasAttachments === true;

// Ignorar emails de planilhas
if (isPlanilha || (hasAttachments && (subject.includes('daily') || subject.includes('shipment')))) {
  console.log('📋 Email de planilha detectado - Ignorando AI');
  return [{
    json: {
