/**
 * Node: Processar Classificação
 * Suporta:
 *  A) items[0].json.output = string JSON já classificada (pass-through com normalização)
 *  B) items[0].json.email  = objeto cru de e-mail (fallback bem básico)
 */

function safe(v, d=null){ return (v === undefined || v === null) ? d : v; }
function isObj(x){ return x && typeof x === 'object' && !Array.isArray(x); }
function toArr(x){ return Array.isArray(x) ? x : (x ? [x] : []); }

function parseMaybeJSON(str){
  if (typeof str !== 'string') return null;
  try { return JSON.parse(str); } catch { return null; }
}

function normBool(x, def){
  if (typeof x === 'boolean') return x;
  if (x === 'true') return true;
  if (x === 'false') return false;
  return def;
}

function normalizeRecord(r){
  // NÃO reclassifica. Só garante os campos e defaults.
  const tipo_email = safe(r.tipo_email, 'pre_alerta');

  // Regra: se já é confirmação de embarque, previsão de embarque deve ficar null
  const previsao_embarque =
    (tipo_email === 'confirmacao_embarque') ? null : safe(r.previsao_embarque, null);

  return {
    deve_processar: normBool(r.deve_processar, true),
    tipo_email,
    numero_carga: safe(r.numero_carga, null),
    localizacao: safe(r.localizacao, null),
    awb_number: safe(r.awb_number, null),
    hawb_number: safe(r.hawb_number, null),
    previsao_embarque,
    previsao_chegada: safe(r.previsao_chegada, null),
    data_evento: safe(r.data_evento, null),
    invoices: toArr(r.invoices),
    observacoes: safe(r.observacoes, null),
    updated_at: new Date().toISOString(),
    fonte: 'email',
  };
}

// === Entrada ===
const input = items[0].json || {};

// 1) Caminho principal: veio como string JSON em `output`
let parsed = parseMaybeJSON(input.output);

if (parsed && isObj(parsed)) {
  // Se o JSON vem embrulhado (ex.: { output: {...} } ou { data: {...} }), tenta abrir uma camada
  if (isObj(parsed.output)) parsed = parsed.output;
  if (isObj(parsed.data)) parsed = parsed.data;

  const out = normalizeRecord(parsed);
  return [{ json: out }];
}

// 2) Fallback (bem conservador) se não veio `output` em JSON
//    Tenta extrair pouquíssimo do e-mail só para não quebrar fluxo.
const email = input.email || {};
const subject = email.subject || '';
const body = (email.bodyPreview || email.originalBody || '');

function pickPO(s){
  const m = s.match(/\bPO\s*[-:]?\s*(\d+)\b/i);
  return m ? m[1] : null;
}
function pickMAWB(s){
  const m = s.match(/\b(\d{3})[-\s]?(\d{4})[-\s]?(\d{4})\b/);
  return m ? `${m[1]}-${m[2]} ${m[3]}` : null;
}
function pickHAWB(s){
  const m = s.match(/\bHAWB[:\s-]*([A-Z]{2,}\d{3,})\b/i) || s.match(/\b(MIA\d{4,})\b/i);
  return m ? m[1].toUpperCase() : null;
}
function pickInvoices(s){
  const set = new Set();
  (s.match(/\b\d{7,}\b/g) || []).forEach(n => set.add(n));
  return Array.from(set);
}

const fallback = {
  deve_processar: true,
  tipo_email: 'pre_alerta',
  numero_carga: pickPO(subject) || null,
  localizacao: /miami/i.test(body) ? 'Miami' : null,
  awb_number: pickMAWB(subject + ' ' + body),
  hawb_number: pickHAWB(subject + ' ' + body),
  previsao_embarque: null,
  previsao_chegada: null,
  data_evento: null,
  invoices: pickInvoices(subject + ' ' + body),
