// Função para extrair thread completa removendo HTML mas mantendo conteúdo
function extractEmailThread(emailBody) {
  if (!emailBody || typeof emailBody !== 'string') return '';

  // Remove HTML tags mas mantém conteúdo legível
  let textOnly = emailBody
    .replace(/<style[^>]*>.*?<\/style>/gi, '') // Remove CSS
    .replace(/<script[^>]*>.*?<\/script>/gi, '') // Remove JS
    .replace(/<[^>]+>/g, ' ') // Remove todas as tags HTML
    .replace(/&nbsp;/g, ' ') // Converte &nbsp; em espaço
    .replace(/&amp;/g, '&') // Converte &amp; em &
    .replace(/&lt;/g, '<') // Converte &lt; em <
    .replace(/&gt;/g, '>') // Converte &gt; em >
    .replace(/&quot;/g, '"') // Converte &quot; em "
    .replace(/&#39;/g, "'") // Converte &#39; em '
    .replace(/\s+/g, ' ') // Normaliza espaços múltiplos
    .trim();

  return textOnly;
}

